/* ------------ Compression d'images avant stockage (fix crash) ------------
   Les photos prises avec un téléphone pèsent souvent 3 à 12 Mo. Les
   convertir telles quelles en dataURL base64 et les empiler dans
   localStorage (quota ~5-10 Mo par site) fait planter/geler l'appli dès
   qu'on ajoute 1-2 fonds d'écran ou qu'on crée quelques séries/films avec
   pochette. Cette fonction redimensionne + compresse via <canvas> AVANT
   de générer le dataURL, ce qui règle le problème à la source. */
function fileToResizedDataURL(file, maxDim = 640, quality = 0.72){
  return new Promise((resolve, reject)=>{
    const reader = new FileReader();
    reader.onerror = ()=> reject(reader.error);
    reader.onload = ()=>{
      const img = new Image();
      img.onerror = ()=> resolve(reader.result); // fallback si décodage échoue
      img.onload = ()=>{
        try{
          let { width, height } = img;
          if(width > maxDim || height > maxDim){
            if(width >= height){ height = Math.round(height * (maxDim / width)); width = maxDim; }
            else{ width = Math.round(width * (maxDim / height)); height = maxDim; }
          }
          const canvas = document.createElement('canvas');
          canvas.width = width; canvas.height = height;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(img, 0, 0, width, height);
          resolve(canvas.toDataURL('image/jpeg', quality));
        }catch(e){ resolve(reader.result); }
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

/* ------------ Compression des photos utilisées comme fond 360° / média ------------
   Une photo de téléphone (souvent 4000-8000px de large) chargée telle quelle comme
   texture a-sky, ET dupliquée pour les deux yeux (rendu stéréo), dépasse largement
   la mémoire vidéo dispo sur mobile → crash "Aw, Snap!". On la redimensionne donc
   via <canvas> et on la reconvertit en Blob AVANT de créer l'URL utilisée comme
   texture ou de la sauvegarder dans IndexedDB (bonus : stockage bien plus léger). */
function resizeImageFileToBlob(file, maxDim = 2048, quality = 0.82){
  return new Promise((resolve)=>{
    const url = URL.createObjectURL(file);
    const img = new Image();
    img.onerror = ()=>{ URL.revokeObjectURL(url); resolve(file); }; // fallback : fichier original
    img.onload = ()=>{
      try{
        let { width, height } = img;
        if(width > maxDim || height > maxDim){
          if(width >= height){ height = Math.round(height * (maxDim / width)); width = maxDim; }
          else{ width = Math.round(width * (maxDim / height)); height = maxDim; }
        }
        const canvas = document.createElement('canvas');
        canvas.width = width; canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, width, height);
        canvas.toBlob(blob=>{
          URL.revokeObjectURL(url);
          resolve(blob || file);
        }, 'image/jpeg', quality);
      }catch(e){ URL.revokeObjectURL(url); resolve(file); }
    };
    img.src = url;
  });
}

